#include <iostream>

using namespace std;

class Solution {
	public:
		int find_missing_element(vector<int>& nums) {
			for (int i = 0; i < nums.size(); i++) {
				if (i not in nums) {
					return i;
				}
			}
			return -1;
		}
	};

tint main() {
		ios_base::sync_with_stdio(false);
		cin.tie(nullptr);

		Solution solution;
		vector<int> nums = {1, 2, 3, 5};
		int result = solution.find_missing_element(nums);
		cout << result << endl;
		return 0;
}
